mapper.select:
SELECT e.equipment_id, e.equipment_name, e.equipment_status, ep.equipment_process_name, wd.employee_id AS manager_id, emp.employee_name AS manager_name, emp.employee_tier AS manager_tier FROM equipment e JOIN equipment_process ep ON e.equipment_process_id = ep.equipment_process_id JOIN worker_deployment wd ON e.equipment_id = wd.equipment_id AND wd.employee_id IN
#{id}
AND (wd.end_date IS NULL OR wd.end_date >= CURDATE()) JOIN employee emp ON wd.employee_id = emp.employee_id WHERE COALESCE(e.is_deleted, false) = false
